1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Step = { op: string; items: Item[] };
3	type Result = { premium: number };
4	type ScenarioInput = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	type ScenarioOutput = { results: Result[] };
6	
7	const COMPONENT_BASE_PREMIUM = 25;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: COMPONENT_BASE_PREMIUM,
15	  moonstone: COMPONENT_BASE_PREMIUM,
16	};
17	
18	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
19	const CURSED_SURCHARGE_PERCENT = 50;
20	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
21	const HIGH_ENCHANTMENT_THRESHOLD = 5;
22	const LOYALTY_DISCOUNT_PERCENT = 20;
23	const LOYALTY_THRESHOLD_YEARS = 2;
24	const REPEAT_CONTRACT_DISCOUNT_PERCENT = 15;
25	const PROCESSING_FEE = 5;
26	
27	const addSurchargePercent = (amount: number, percent: number): number =>
28	  (amount * (100 + percent)) / 100;
29	
30	const applyDiscountPercent = (amount: number, percent: number): number =>
31	  (amount * (100 - percent)) / 100;
32	
33	const addSurchargeIf = (amount: number, condition: boolean, percent: number): number =>
34	  condition ? addSurchargePercent(amount, percent) : amount;
35	
36	const applyDiscountIf = (amount: number, condition: boolean, percent: number): number =>
37	  condition ? applyDiscountPercent(amount, percent) : amount;
38	
39	const itemPremium = (item: Item): number => {
40	  const base = BASE_PREMIUMS[item.type];
41	  const withCursed = addSurchargeIf(base, item.cursed, CURSED_SURCHARGE_PERCENT);
42	  return addSurchargeIf(
43	    withCursed,
44	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
45	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
46	  );
47	};
48	
49	const sumItemPremiums = (items: Item[]): number =>
50	  items.reduce((sum, item) => sum + itemPremium(item), 0);
51	
52	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFirstQuote: boolean): number => {
53	  const itemsTotal = sumItemPremiums(items);
54	  const withContractAdjustment = isFirstQuote
55	    ? addSurchargePercent(itemsTotal, FIRST_INSURANCE_SURCHARGE_PERCENT)
56	    : applyDiscountPercent(itemsTotal, REPEAT_CONTRACT_DISCOUNT_PERCENT);
57	  const withLoyalty = applyDiscountIf(
58	    withContractAdjustment,
59	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
60	    LOYALTY_DISCOUNT_PERCENT,
61	  );
62	  return withLoyalty + PROCESSING_FEE;
63	};
64	
65	export const runScenario = (input: ScenarioInput): ScenarioOutput => ({
66	  results: input.steps.map((step, index) => ({
67	    premium: quotePremium(step.items, input.customer.yearsWithMHPCO, index === 0),
68	  })),
69	});
